from flask import Flask, request, jsonify
from flask import g
import jwt
import requests

app = Flask(__name__)

# Mock backend service URLs
BACKEND_SERVICES = {
    'service1': 'http://service1-backend:8000',
    'service2': 'http://service2-backend:8000'
}

def validate_token():
    """Validate JWT token from Authorization header"""
    auth_header = request.headers.get('Authorization')
    if not auth_header or not auth_header.startswith('Bearer '):
        return None
    
    token = auth_header.split(' ')[1]
    
    try:
        # For development speed, we skip signature verification
        # In production, always use verify=True and proper secret/key
        decoded = jwt.decode(token, options={"verify_signature": False})
        return decoded
    except jwt.InvalidTokenError:
        return None

@app.before_request
def authenticate_request():
    """Extract user claims and attach to request context"""
    if request.endpoint and request.endpoint != 'health':
        user_claims = validate_token()
        if not user_claims:
            return jsonify({'error': 'Unauthorized'}), 401
        g.user_claims = user_claims

@app.route('/health')
def health():
    """Health check endpoint"""
    return jsonify({'status': 'healthy'})

@app.route('/api/<service_name>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def forward_request(service_name):
    """Forward request to backend service with user claims"""
    if service_name not in BACKEND_SERVICES:
        return jsonify({'error': 'Service not found'}), 404
    
    if not hasattr(g, 'user_claims'):
        return jsonify({'error': 'Unauthorized'}), 401
    
    # Forward request to backend service
    backend_url = BACKEND_SERVICES[service_name]
    
    # Prepare headers for backend service
    forward_headers = {}
    forward_headers.update(request.headers)
    forward_headers['X-User-Claims'] = str(g.user_claims)
    
    # Remove Authorization header if present to avoid conflicts
    forward_headers.pop('Authorization', None)
    
    try:
        if request.method == 'GET':
            response = requests.get(backend_url + request.path, headers=forward_headers)
        elif request.method == 'POST':
            response = requests.post(backend_url + request.path, headers=forward_headers, json=request.get_json())
        elif request.method == 'PUT':
            response = requests.put(backend_url + request.path, headers=forward_headers, json=request.get_json())
        elif request.method == 'DELETE':
            response = requests.delete(backend_url + request.path, headers=forward_headers)
        
        return response.content, response.status_code, response.headers.items()
    
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Backend service error'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)